opencat.script:
ctx.fromTo('hero-wrap', {opacity: 0, y: 22, scale: 1.04}, {opacity: 1, y: 0, scale: 1, duration: 0.65, delay: 0.18, ease: 'power3.out'});
ctx.fromTo('ghost', {opacity: 0, x: -28}, {opacity: 0.06, x: 0, duration: 0.8, delay: 0.05, ease: 'power2.out'});
ctx.to('ghost', {x: 18, duration: 4.5, repeat: -1, yoyo: true, ease: 'sine.inOut', delay: 0.6});
ctx.to('meter-fill', {width: 700, duration: 1.8, repeat: -1, yoyo: true, ease: 'sine.inOut', delay: 0.8});

ctx.to('hero-before', {
  keyframes: {
    clipPath: [
      'inset(20% 0% 80% 0%)',
      'inset(60% 0% 10% 0%)',
      'inset(40% 0% 50% 0%)',
      'inset(80% 0% 5% 0%)',
      'inset(10% 0% 70% 0%)',
      'inset(30% 0% 50% 0%)'
    ],
    x: [-2, 2, -2, 1, -1, 2],
    y: [1, -1, 2, -2, 1, -1]
  },
  duration: 2,
  repeat: -1,
  yoyo: true,
  ease: 'linear',
  delay: 0.35
});

ctx.to('hero-after', {
  keyframes: {
    clipPath: [
      'inset(10% 0% 60% 0%)',
      'inset(80% 0% 5% 0%)',
      'inset(30% 0% 20% 0%)',
      'inset(10% 0% 80% 0%)',
      'inset(50% 0% 30% 0%)',
      'inset(20% 0% 70% 0%)'
    ],
    x: [2, -2, 1, -1, 2, -2],
    y: [-1, 2, -2, 1, -1, 1]
  },
  duration: 3,
  repeat: -1,
  yoyo: true,
  ease: 'linear',
  delay: 0.35
});

ctx.to('hero', {skewX: 2, x: -2, duration: 0.06, repeat: -1, yoyo: true, ease: 'steps(1)', delay: 1.0});
ctx.to('scan', {opacity: 0.72, duration: 0.22, repeat: -1, yoyo: true, ease: 'steps(1)', delay: 0.5});
